#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ; 
}
const int N=3e5+10,M=6e5+10;
struct SAM{map<int,int>ch;int fa,len,siz;}t[N];char s[N];
struct Graph
{
	int head[N],des[M],nxt[M],cnt;
	inline void ins(int x,int y){des[++cnt]=y;nxt[cnt]=head[x];head[x]=cnt;}
	inline void Init(bool q=0){memset(head,0,sizeof(head));cnt=q;}
}a;
int lst=1,cnt=1;long long ans;
inline void ins(int c)
{
	int p=lst,np=lst=++cnt;t[np].len=t[p].len+1;
	for(;p&&!t[p].ch[c];p=t[p].fa)t[p].ch[c]=np;
	if(!p){t[np].fa=1;}
	else
	{
		int v=t[p].ch[c];
		if(t[v].len==t[p].len+1){t[np].fa=v;}
		else
		{
			int nv=++cnt;t[nv]=t[v];t[nv].len=t[p].len+1;
			for(;p&&t[p].ch[c]==v;p=t[p].fa)t[p].ch[c]=nv;
			t[np].fa=t[v].fa=nv;
		}
	}
	ans+=t[np].len-t[t[np].fa].len;
}
int main(){int n=read();rep(1,n,i)ins(read()),printf("%lld\n",ans);}
